import re

class LexicalAnalyzer:
 def __init__(self, source_code):
 self.source_code = source_code
 self.tokens = []

 def run(self):
 while self.source_code:
 lexeme = self.get_next_lexeme()
 token = self.get_token(lexeme)
 if token:
 self.tokens.append(token)
 else:
 self.handle_lexical_error(lexeme)

 def get_next_lexeme(self):
 # Simplified implementation, does not handle all edge cases
 return self.source_code.pop(0)

 def get_token(self, lexeme):
 # Simplified implementation, does not handle all token types
 if re.match(r'[a-zA-Z_][a-zA-Z_0-9]*', lexeme):
 return {'type': 'IDENTIFIER', 'value': lexeme}
 elif re.match(r'[0-9]+', lexeme):
 return {'type': 'INTEGER', 'value': int(lexeme)}
 else:
 return None

 def handle_lexical_error(self, lexeme):
 print(f'Lexical error: {lexeme}')

