#include <ctype.h>

#define MAX_TOKEN_LENGTH 1024

char token[MAX_TOKEN_LENGTH];

void lexical_analyzer(char *source_code) {
 while (*source_code) {
 // Simplified implementation, does not handle all edge cases
 if (isalpha(*source_code)) {
 // Handle identifier
 int i = 0;
 while (isalnum(*source_code)) {
 token[i++] = *source_code;
 source_code++;
 }
 token[i] = '\0';
 printf("IDENTIFIER: %s\n", token);
 } else if (isdigit(*source_code)) {
 // Handle integer
 int value = 0;
 while (isdigit(*source_code)) {
 value = value * 10 + (*source_code - '0');
 source_code++;
 }
 printf("INTEGER: %d\n", value);
 } else {
 // Handle error
 printf("Lexical error: %c\n", *source_code);
 source_code++;
 }
 }
}
